module RefModule(clock,signal_uc, prog_or_kernel,reset);input signal_uc;
	input clock;
	input reset;
	output prog_or_kernel;
	reg unused_state;


	always @(posedge clock) begin
		if(reset)begin
			unused_state <= 0;
		end
		if((signal_uc == 1) && (unused_state == 0))begin
			unused_state <= 1;
		end 
		else if((signal_uc == 1) && (unused_state == 1)) begin
			unused_state <= 0;
		end

	end
	assign prog_or_kernel = unused_state;


endmodule
